/**
 * Tests for children-bus — M168 Phase 4 (#1914)
 *
 * Verifies the atomic write contract (tmp+rename), the read-after-write
 * round-trip, multi-child enumeration, and orphan sweeping.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import {
  existsSync,
  mkdtempSync,
  readFileSync,
  readdirSync,
  rmSync,
  writeFileSync,
} from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import {
  childrenDir,
  deleteChild,
  listChildren,
  readChildState,
  sweepOrphanChildren,
  writeChildState,
} from '../../lib/children-bus.js';

describe('lib/children-bus (#1914)', () => {
  let parentDir: string;

  beforeEach(() => {
    parentDir = mkdtempSync(join(tmpdir(), 'ork-children-bus-'));
  });

  afterEach(() => {
    rmSync(parentDir, { recursive: true, force: true });
  });

  it('writeChildState creates the directory + writes a parseable JSON file', () => {
    writeChildState(parentDir, 's-child-1', { status: 'running', step: 3 });
    const dir = childrenDir(parentDir);
    expect(existsSync(dir)).toBe(true);

    const target = join(dir, 's-child-1.json');
    expect(existsSync(target)).toBe(true);

    const raw = readFileSync(target, 'utf8');
    const parsed = JSON.parse(raw);
    expect(parsed).toEqual({ status: 'running', step: 3 });
  });

  it('writeChildState is atomic — no .tmp file remains on success', () => {
    writeChildState(parentDir, 's-child-2', { phase: 'init' });
    const dir = childrenDir(parentDir);
    const entries = readdirSync(dir);
    // Should contain only the final file, no leftover tmp.
    expect(entries.some(e => e.includes('.tmp.'))).toBe(false);
    expect(entries).toContain('s-child-2.json');
  });

  it('readChildState round-trips the payload', () => {
    const payload = { status: 'paused', detail: { reason: 'rate-limit' } };
    writeChildState(parentDir, 's-child-3', payload);
    expect(readChildState(parentDir, 's-child-3')).toEqual(payload);
  });

  it('readChildState returns null when the file is absent', () => {
    expect(readChildState(parentDir, 's-missing')).toBeNull();
  });

  it('readChildState returns null when the file is corrupt JSON', () => {
    const dir = childrenDir(parentDir);
    // mkdir + dump a non-JSON file directly
    writeChildState(parentDir, 's-good', { ok: true });
    writeFileSync(join(dir, 's-corrupt.json'), '{not json');
    expect(readChildState(parentDir, 's-corrupt')).toBeNull();
    // Other entries still readable.
    expect(readChildState(parentDir, 's-good')).toEqual({ ok: true });
  });

  it('listChildren enumerates every child + skips corrupt files', () => {
    writeChildState(parentDir, 's-a', { rank: 1 });
    writeChildState(parentDir, 's-b', { rank: 2 });
    writeChildState(parentDir, 's-c', { rank: 3 });
    // Corrupt entry should not appear in listChildren output.
    writeFileSync(join(childrenDir(parentDir), 's-bad.json'), '{bad');

    const out = listChildren(parentDir).sort((x, y) => x.sid.localeCompare(y.sid));
    expect(out.map(r => r.sid)).toEqual(['s-a', 's-b', 's-c']);
    expect(out.find(r => r.sid === 's-b')?.payload).toEqual({ rank: 2 });
  });

  it('listChildren returns [] when the directory does not exist yet', () => {
    expect(listChildren(parentDir)).toEqual([]);
  });

  it('deleteChild removes just that file + leaves siblings alone', () => {
    writeChildState(parentDir, 's-keep', { rank: 1 });
    writeChildState(parentDir, 's-drop', { rank: 2 });
    deleteChild(parentDir, 's-drop');

    expect(readChildState(parentDir, 's-drop')).toBeNull();
    expect(readChildState(parentDir, 's-keep')).toEqual({ rank: 1 });
  });

  it('deleteChild is a no-op when the file is already gone', () => {
    // Should not throw.
    expect(() => deleteChild(parentDir, 's-not-here')).not.toThrow();
  });

  it('sweepOrphanChildren removes sids not in the live set', () => {
    writeChildState(parentDir, 's-live-1', { rank: 1 });
    writeChildState(parentDir, 's-live-2', { rank: 2 });
    writeChildState(parentDir, 's-dead', { rank: 99 });

    sweepOrphanChildren(parentDir, new Set(['s-live-1', 's-live-2']));

    expect(readChildState(parentDir, 's-live-1')).not.toBeNull();
    expect(readChildState(parentDir, 's-live-2')).not.toBeNull();
    expect(readChildState(parentDir, 's-dead')).toBeNull();
  });

  it('sweepOrphanChildren is a no-op when the directory does not exist', () => {
    expect(() => sweepOrphanChildren(parentDir, new Set())).not.toThrow();
  });

  it('sweepOrphanChildren leaves everything when liveSids covers all sids', () => {
    writeChildState(parentDir, 's-a', { rank: 1 });
    writeChildState(parentDir, 's-b', { rank: 2 });
    sweepOrphanChildren(parentDir, new Set(['s-a', 's-b']));
    expect(listChildren(parentDir).length).toBe(2);
  });

  it('writeChildState overwrites prior state for the same sid', () => {
    writeChildState(parentDir, 's-x', { rev: 1 });
    writeChildState(parentDir, 's-x', { rev: 2 });
    expect(readChildState(parentDir, 's-x')).toEqual({ rev: 2 });
  });

  it('multiple children are isolated — writing one never disturbs others', () => {
    writeChildState(parentDir, 's-1', { tag: 'first' });
    writeChildState(parentDir, 's-2', { tag: 'second' });
    writeChildState(parentDir, 's-1', { tag: 'first-updated' });

    expect(readChildState(parentDir, 's-1')).toEqual({ tag: 'first-updated' });
    expect(readChildState(parentDir, 's-2')).toEqual({ tag: 'second' });
  });
});
